import { Schema, model, Document, Types } from 'mongoose';

export interface Group extends Document {
  name: string;
  description: string;
  adminId: Types.ObjectId;
  members: Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true },
  members: { type: [Schema.Types.ObjectId], default: [] },
  telegramChatId: { type: String, default: null },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model<Group>('Group', groupSchema);

import { Types } from 'mongoose';

export interface CreateGroupDTO {
  name: string;
  description: string;
  adminId: Types.ObjectId;
}

export interface UpdateTelegramChatIdDTO {
  telegramChatId: string;
}

export interface GroupResponseDTO {
  id: Types.ObjectId;
  name: string;
  description: string;
  adminId: Types.ObjectId;
  members: Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

import { GroupModel, Group } from './group.model';
import { Types } from 'mongoose';

export class GroupRepository {
  async createGroup(data: Partial<Group>): Promise<Group> {
    const group = new GroupModel(data);
    return group.save();
  }

  async findGroupById(id: Types.ObjectId): Promise<Group | null> {
    return GroupModel.findById(id).exec();
  }

  async updateTelegramChatId(id: Types.ObjectId, telegramChatId: string): Promise<Group | null> {
    return GroupModel.findByIdAndUpdate(
      id,
      { telegramChatId },
      { new: true }
    ).exec();
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO, UpdateTelegramChatIdDTO, GroupResponseDTO } from './group.dto';
import { Types } from 'mongoose';

export class GroupService {
  private repository: GroupRepository;

  constructor() {
    this.repository = new GroupRepository();
  }

  async createGroup(dto: CreateGroupDTO): Promise<GroupResponseDTO> {
    const group = await this.repository.createGroup(dto);
    return this.toResponseDTO(group);
  }

  async getGroup(id: Types.ObjectId): Promise<GroupResponseDTO | null> {
    const group = await this.repository.findGroupById(id);
    return group ? this.toResponseDTO(group) : null;
  }

  async linkTelegramChat(id: Types.ObjectId, dto: UpdateTelegramChatIdDTO): Promise<GroupResponseDTO | null> {
    const group = await this.repository.updateTelegramChatId(id, dto.telegramChatId);
    return group ? this.toResponseDTO(group) : null;
  }

  private toResponseDTO(group: Group): GroupResponseDTO {
    return {
      id: group._id,
      name: group.name,
      description: group.description,
      adminId: group.adminId,
      members: group.members,
      telegramChatId: group.telegramChatId,
      createdAt: group.createdAt
    };
  }
}

import { Request, Response } from 'express';
import { GroupService } from './group.service';
import { CreateGroupDTO, UpdateTelegramChatIdDTO } from './group.dto';

export class GroupController {
  private service: GroupService;

  constructor() {
    this.service = new GroupService();
  }

  async createGroup(req: Request, res: Response): Promise<void> {
    try {
      const dto: CreateGroupDTO = req.body;
      const group = await this.service.createGroup(dto);
      res.status(201).json({ success: true, data: group });
    } catch (error) {
      this.handleError(res, error);
    }
  }

  async getGroup(req: Request, res: Response): Promise<void> {
    try {
      const groupId = req.params.id;
      const group = await this.service.getGroup(new Types.ObjectId(groupId));
      res.status(200).json({ success: true, data: group });
    } catch (error) {
      this.handleError(res, error);
    }
  }

  async linkTelegramChat(req: Request, res: Response): Promise<void> {
    try {
      const groupId = req.params.id;
      const dto: UpdateTelegramChatIdDTO = req.body;
      const group = await this.service.linkTelegramChat(new Types.ObjectId(groupId), dto);
      res.status(200).json({ success: true, data: group });
    } catch (error) {
      this.handleError(res, error);
    }
  }

  private handleError(res: Response, error: any): void {
    res.status(500).json({
      success: false,
      message: error.message || 'Internal Server Error',
      data: null
    });
  }
}

import { z } from 'zod';

export const createGroupSchema = z.object({
  name: z.string().min(1),
  description: z.string().min(1),
  adminId: z.string().refine((val) => /^[a-fA-F0-9]{24}$/.test(val), {
    message: 'Invalid ObjectId format'
  })
});

export const updateTelegramChatIdSchema = z.object({
  telegramChatId: z.string().min(1)
});
